@app.route("/api/orders", methods=["POST"])
@track_requests
def create_order():
    """Create order endpoint with business metrics."""
    order_type = random.choice(["standard", "express", "premium"])
    product_category = random.choice(["electronics", "clothing", "food", "books"])
    order_amount = round(random.uniform(10.0, 500.0), 2)

    # Simulate order processing
    processing_start = time.time()
    simulate_db_query("insert", "orders")
    time.sleep(random.uniform(0.05, 0.5))
    processing_duration = time.time() - processing_start

    # Determine order status
    status = random.choices(["completed", "failed", "pending"], weights=[85, 5, 10])[0]

    # Record business metrics
    ORDERS_TOTAL.labels(order_type=order_type, status=status).inc()
    ORDER_PROCESSING_TIME.labels(order_type=order_type).observe(processing_duration)

    if status == "completed":
        REVENUE_TOTAL.labels(product_category=product_category).inc(order_amount)

    # Update queue size
    QUEUE_SIZE.labels(queue_name="orders").set(random.randint(0, 50))

    if status == "failed":
        ERRORS_TOTAL.labels(error_type="OrderProcessingError", endpoint="/api/orders").inc()

    return jsonify({
        "order_id": random.randint(10000, 99999),
        "order_type": order_type,
        "product_category": product_category,
        "amount": order_amount,
        "status": status,
        "processing_time_ms": round(processing_duration * 1000, 2),
    }), 201 if status != "failed" else 500


