@app.route("/api/health")
@track_requests
def health_check():
    """Health check endpoint that updates system health gauges."""
    components = {
        "database": random.choices([True, False], weights=[95, 5])[0],
        "cache": random.choices([True, False], weights=[98, 2])[0],
        "message_queue": random.choices([True, False], weights=[97, 3])[0],
        "external_api": random.choices([True, False], weights=[90, 10])[0],
    }

    for component, is_healthy in components.items():
        SYSTEM_HEALTH.labels(component=component).set(1 if is_healthy else 0)

    overall_healthy = all(components.values())

    return jsonify({
        "status": "healthy" if overall_healthy else "degraded",
        "components": {k: "up" if v else "down" for k, v in components.items()},
    }), 200 if overall_healthy else 503


