@app.route("/api/simulate-error")
@track_requests
def simulate_error():
    """Endpoint to simulate errors for testing alerting."""
    error_type = request.args.get("type", "random")

    if error_type == "500" or (error_type == "random" and random.random() < 0.5):
        ERRORS_TOTAL.labels(
            error_type="InternalServerError", endpoint="/api/simulate-error"
        ).inc()
        return jsonify({"error": "Internal Server Error"}), 500
    elif error_type == "timeout":
        time.sleep(random.uniform(5.0, 10.0))
        ERRORS_TOTAL.labels(
            error_type="TimeoutError", endpoint="/api/simulate-error"
        ).inc()
        return jsonify({"error": "Request Timeout"}), 504
    elif error_type == "400":
        ERRORS_TOTAL.labels(
            error_type="BadRequest", endpoint="/api/simulate-error"
        ).inc()
        return jsonify({"error": "Bad Request"}), 400
    else:
        return jsonify({"message": "No error this time!"}), 200


