# --- Error handlers ---

@app.errorhandler(404)
def not_found(error):
    REQUEST_COUNT.labels(
        method=request.method, endpoint=request.path, http_status=404
    ).inc()
    ERRORS_TOTAL.labels(error_type="NotFound", endpoint=request.path).inc()
    return jsonify({"error": "Not Found"}), 404


@app.errorhandler(500)
def internal_error(error):
    REQUEST_COUNT.labels(
        method=request.method, endpoint=request.path, http_status=500
    ).inc()
    ERRORS_TOTAL.labels(error_type="InternalServerError", endpoint=request.path).inc()
    return jsonify({"error": "Internal Server Error"}), 500


